use anyhow::{anyhow, Result};
use gnosis_polyglot::cfg::{CfgNodeKind, ControlFlowGraph};
use gnosis_polyglot::source_map::SourceSpan;
use serde_json::Value;
use std::collections::{BTreeMap, HashMap};

pub fn compile_gnot_to_cfg(source: &str, file_path: &str) -> Result<ControlFlowGraph> {
    let ir = gnot::parse_and_compile(source).map_err(|e| anyhow!("Gnot compile error: {:?}", e))?;
    let gg = gnot::emit_orchestration_gg(&ir, file_path);

    compile_orchestration_scan_value(
        &gg,
        file_path,
        "gnot",
        "Gnot file contains no flows or stanzas",
    )
}

pub fn compile_gnarly_to_cfg(source: &str, file_path: &str) -> Result<ControlFlowGraph> {
    let orchestration =
        gnosis_polyglot::gnarly::parse_and_extract_gnarly_orchestration(source, file_path)?;
    let gg = serde_json::to_value(&orchestration.scan_result)?;

    compile_orchestration_scan_value(
        &gg,
        file_path,
        "gnarly",
        "Gnarly file contains no executable topology",
    )
}

fn compile_orchestration_scan_value(
    gg: &Value,
    file_path: &str,
    language: &str,
    empty_message: &str,
) -> Result<ControlFlowGraph> {
    // We expect at least one topology (the main flow or stanza)
    let topologies = gg
        .get("topologies")
        .and_then(Value::as_array)
        .ok_or_else(|| anyhow!("No topologies found in orchestration IR"))?;

    if topologies.is_empty() {
        return Err(anyhow!(empty_message.to_string()));
    }

    // For Moonshine, we'll take the first topology as "main"
    let topo_data = &topologies[0];
    let function_name = topo_data
        .get("function_name")
        .and_then(Value::as_str)
        .unwrap_or("main")
        .to_string();
    let topo = topo_data
        .get("topology")
        .ok_or_else(|| anyhow!("Missing topology data"))?;

    let mut cfg = ControlFlowGraph::new(function_name, language.to_string(), file_path.to_string());

    let nodes = topo
        .get("nodes")
        .and_then(Value::as_array)
        .ok_or_else(|| anyhow!("Missing nodes"))?;
    let edges = topo
        .get("edges")
        .and_then(Value::as_array)
        .ok_or_else(|| anyhow!("Missing edges"))?;

    let mut id_map: HashMap<String, usize> = HashMap::new();

    for node_val in nodes {
        let id_str = node_val
            .get("id")
            .and_then(Value::as_str)
            .ok_or_else(|| anyhow!("Node missing ID"))?;
        let labels = node_val
            .get("labels")
            .and_then(Value::as_array)
            .ok_or_else(|| anyhow!("Node missing labels"))?;
        let properties = node_val
            .get("properties")
            .and_then(Value::as_object)
            .ok_or_else(|| anyhow!("Node missing properties"))?;

        let mut kind = CfgNodeKind::Statement;
        for label in labels {
            if let Some(l) = label.as_str() {
                match l {
                    "Entry" => {
                        kind = CfgNodeKind::Entry {
                            name: properties
                                .get("name")
                                .and_then(Value::as_str)
                                .unwrap_or("")
                                .to_string(),
                        }
                    }
                    "Return" => kind = CfgNodeKind::Return,
                    "ConcurrentSpawn" => kind = CfgNodeKind::ConcurrentSpawn,
                    _ => {}
                }
            }
        }

        // Special check for Gnot kernel intents
        if let Some(intent) = properties.get("kernel_intent").and_then(Value::as_str) {
            if intent == "fork" || intent == "race" || intent == "pipe" {
                kind = CfgNodeKind::ConcurrentSpawn;
            }
        }

        let mut extra_properties = BTreeMap::new();
        for (k, v) in properties {
            if let Some(s) = v.as_str() {
                extra_properties.insert(k.clone(), s.to_string());
            } else {
                extra_properties.insert(k.clone(), v.to_string());
            }
        }
        if std::env::var("MOONSHINE_VERBOSE").is_ok() {
            eprintln!(
                "[moonshine] compiled {} node {} with props: {:?}",
                language,
                id_str,
                extra_properties.keys()
            );
        }

        // Re-map "callee" to "source" if "source" is missing, for Moonshine's NativeBackend
        if !extra_properties.contains_key("source") {
            if let Some(callee) = extra_properties.get("callee") {
                let mut source = callee.clone();
                if let Some(args_json) = extra_properties.get("args") {
                    if let Ok(args) = serde_json::from_str::<Value>(args_json) {
                        if let Some(arr) = args.as_array() {
                            for arg in arr {
                                // Simple best-effort reconstruct
                                if let Some(lit) = arg.get("value") {
                                    source.push_str(&format!(" {}", lit));
                                } else if let Some(ident) = arg.get("name") {
                                    source.push_str(&format!(" {}", ident));
                                }
                            }
                        }
                    }
                }
                extra_properties.insert("source".to_string(), source);
            }
        }

        let cfg_id = cfg.add_node_with_props(
            kind,
            SourceSpan::synthetic(file_path),
            properties
                .get("name")
                .and_then(Value::as_str)
                .unwrap_or("")
                .to_string(),
            extra_properties,
        );
        id_map.insert(id_str.to_string(), cfg_id);

        if labels.iter().any(|l| l.as_str() == Some("Entry")) {
            cfg.entry = cfg_id;
        }
    }

    for edge_val in edges {
        let sources = edge_val
            .get("source_ids")
            .or_else(|| edge_val.get("sourceIds"))
            .and_then(Value::as_array)
            .ok_or_else(|| anyhow!("Edge missing source_ids"))?;
        let targets = edge_val
            .get("target_ids")
            .or_else(|| edge_val.get("targetIds"))
            .and_then(Value::as_array)
            .ok_or_else(|| anyhow!("Edge missing target_ids"))?;
        let edge_type = edge_val.get("type").and_then(Value::as_str);

        for s in sources {
            for t in targets {
                if let (Some(s_str), Some(t_str)) = (s.as_str(), t.as_str()) {
                    if let (Some(s_id), Some(t_id)) = (id_map.get(s_str), id_map.get(t_str)) {
                        cfg.add_edge(*s_id, *t_id, edge_type.map(|s| s.to_string()));
                    }
                }
            }
        }
    }

    Ok(cfg)
}
